console.log('Funksiya ifadəsi nümunəsi...');
const sayHello = function() {
    console.log('Salam, Dünya!');
};
sayHello();
// Output:
// Funksiya ifadəsi nümunəsi...
// Salam, Dünya!

console.log('Parametrlər və return nümunəsi...');
const addNumbers = function(a, b) {
    const sum = a + b;
    return sum;
};
const result = addNumbers(5, 3);
console.log('Nəticə:', result);
// Output:
// Parametrlər və return nümunəsi...
// Nəticə: 8

console.log('Hoisting olmaması nümunəsi...');
// greet(); // Səhv: greet is not a function
const greet = function() {
    console.log('Salam!');
};
greet();
// Output:
// Hoisting olmaması nümunəsi...
// Salam!

console.log('Funksiya scope-u nümunəsi...');
const showMessage = function() {
    const message = 'Funksiya daxilində';
    console.log(message);
};
showMessage();
// console.log(message); // Səhv: message is not defined
// Output:
// Funksiya scope-u nümunəsi...
// Funksiya daxilində

console.log('Adlandırılmış funksiya ifadəsi nümunəsi...');
const factorial = function fact(n) {
    if (n <= 1) return 1;
    return n * fact(n - 1);
};
console.log('Faktorial:', factorial(5));
// Output:
// Adlandırılmış funksiya ifadəsi nümunəsi...
// Faktorial: 120

console.log('Funksiya ifadəsi vs elan nümunəsi...');
// Funksiya elanı
sayHi(); // İşləyir
function sayHi() {
    console.log('Salam (elan)!');
}
// Funksiya ifadəsi
// sayBye(); // Səhv: sayBye is not a function
const sayBye = function() {
    console.log('Salam (ifadə)!');
};
sayBye();
// Output:
// Funksiya ifadəsi vs elan nümunəsi...
// Salam (elan)!
// Salam (ifadə)!

console.log('var, let, const ilə funksiya ifadəsi nümunəsi...');
const exampleConst = function() {
    console.log('Const ilə');
};
let exampleLet = function() {
    console.log('Let ilə');
};
var exampleVar = function() {
    console.log('Var ilə');
};
exampleConst();
exampleLet();
exampleVar();
// Output:
// var, let, const ilə funksiya ifadəsi nümunəsi...
// Const ilə
// Let ilə
// Var ilə

console.log('Səhvə yol açan nümunə...');
const calculateArea = function(width, height) {
    const area = width * height;
    // return area; // Unutqan return
};
const result = calculateArea(4, 5);
console.log('Nəticə:', result);
// Output:
// Səhvə yol açan nümunə...
// Nəticə: undefined

